import React from 'react';
import './App.css';
import KLineChart from './components/KLineChart';
import UASTLChart from './components/UASTLChart';

function App() {
    return (
        <div className="main-layout">
            <div className="left-panel">
                <KLineChart />
            </div>
            <div className="right-panel">
                <UASTLChart />
            </div>
        </div>
    );
}

export default App;
